window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["beauty-health-safety"] = window.COURSE_LANG["beauty-health-safety"] || {};
window.COURSE_LANG["beauty-health-safety"]["es"] = [
  {"id":1,"q":"Para usarse en un salón de California, un desinfectante debe:","opts":["Estar registrado con la EPA de EE. UU. y demostrar actividad bactericida, fungicida y virucida","Ser cualquier limpiador casero","Ser solo alcohol puro","Mezclarlo el dueño del salón sin etiqueta"],"re":"California exige un desinfectante registrado por la EPA cuya etiqueta muestre actividad bactericida, fungicida y virucida demostrada."},
  {"id":2,"q":"Antes de poder desinfectar un implemento, primero hay que:","opts":["Calentarlo en el microondas","Limpiarlo con agua y jabón para quitar la suciedad visible","Rociarlo con perfume","Remojarlo en agua de la llave durante una hora"],"re":"El desinfectante solo actúa sobre una superficie limpia; hay que quitar la suciedad visible con agua y jabón antes de desinfectar."},
  {"id":3,"q":"Los implementos no eléctricos, como las pinzas de metal, se desinfectan mediante:","opts":["Limpiarlos con una toalla","Sostenerlos bajo el agua corriente","Inmersión total en un desinfectante bien preparado","Dejarlos al sol"],"re":"Las herramientas no eléctricas deben sumergirse por completo en el desinfectante registrado por la EPA, bien preparado, durante el tiempo indicado en la etiqueta."},
  {"id":4,"q":"Las herramientas eléctricas y las cuchillas de cortadora que no se pueden sumergir se desinfectan con:","opts":["Un balde de agua","Aceite de cocina","Nada: nunca necesitan desinfección","Un desinfectante en aerosol o toallita"],"re":"Los artículos que no se pueden sumergir, como las herramientas eléctricas y las tijeras, se desinfectan con un aerosol o toallita registrado por la EPA."},
  {"id":5,"q":"Un recipiente con solución desinfectante en la estación debe:","opts":["Estar etiquetado para identificarlo como solución desinfectante","Estar sin etiqueta","Tener el nombre del cliente","Estar oculto de la vista"],"re":"El recipiente del desinfectante debe estar etiquetado (por ejemplo, «Solución desinfectante») para identificar claramente su contenido."},
  {"id":6,"q":"La solución desinfectante debe cambiarse:","opts":["Una vez al año","Según las instrucciones del fabricante o cuando esté turbia o contenga residuos","Nunca","Solo cuando se acaba"],"re":"Reemplaza la solución según las indicaciones del fabricante, o antes si se pone turbia o tiene residuos visibles."},
  {"id":7,"q":"Una caja de luz «esterilizadora» UV en un salón se usa correctamente para:","opts":["Desinfectar implementos en vez de usar químicos","Esterilizar las herramientas por completo","Guardar herramientas ya limpias y desinfectadas","Matar todos los virus al contacto"],"re":"Las cajas UV no desinfectan ni esterilizan de forma confiable; solo sirven para guardar implementos que ya fueron limpiados y desinfectados."},
  {"id":8,"q":"¿Qué proceso elimina toda forma de vida microbiana, incluidas las esporas bacterianas?","opts":["Higienizar con una toallita","Enjuagar con agua","Quitar el polvo","Esterilización (p. ej., una autoclave)"],"re":"La esterilización, como con una autoclave, destruye todos los microorganismos incluidas las esporas: el nivel más alto de descontaminación."},
  {"id":9,"q":"Ordena estos del nivel más bajo al más alto de descontaminación:","opts":["Limpiar, desinfectar, esterilizar","Esterilizar, desinfectar, limpiar","Desinfectar, limpiar, esterilizar","Limpiar, esterilizar, desinfectar"],"re":"Limpiar quita los residuos, desinfectar destruye la mayoría de los patógenos y esterilizar elimina toda vida microbiana incluidas las esporas."},
  {"id":10,"q":"Los tres patógenos transmitidos por sangre de mayor preocupación en un salón son:","opts":["El resfriado común, la gripe y el estreptococo","Hepatitis B, hepatitis C y VIH","Pie de atleta, tiña y caspa","Conjuntivitis, acné y verrugas"],"re":"La norma de patógenos transmitidos por sangre de OSHA se centra en la hepatitis B (VHB), la hepatitis C (VHC) y el VIH."},
  {"id":11,"q":"Según las precauciones universales (estándar), debes tratar:","opts":["Solo la sangre de clientes que se ven enfermos como un peligro","La sangre como inofensiva si es poca","Toda la sangre y los fluidos corporales humanos como potencialmente infecciosos","Tu propia sangre como el único riesgo"],"re":"Las precauciones universales significan tratar la sangre y los fluidos de todo cliente como si pudieran portar un patógeno transmitido por sangre."},
  {"id":12,"q":"¿Qué virus transmitido por sangre es el más resistente y puede sobrevivir más tiempo en superficies secas?","opts":["VIH","Influenza","Ninguno sobrevive fuera del cuerpo","Hepatitis B (VHB)"],"re":"La hepatitis B es especialmente resistente y puede seguir siendo infecciosa en superficies secas mucho más que el VIH, por eso es esencial una desinfección minuciosa."},
  {"id":13,"q":"Si haces un corte a un cliente y aparecen unas gotas de sangre, primero debes:","opts":["Detener el servicio y ponerte guantes","Seguir trabajando e ignorarlo","Limpiarlo con una toalla compartida","Continuar con la misma herramienta sin desinfectar"],"re":"Detén el servicio de inmediato y ponte guantes antes de manipular cualquier sangre, para protegerte a ti y al cliente."},
  {"id":14,"q":"Tras una lesión del cliente que produce sangre, la herida del cliente debe:","opts":["Dejarse abierta","Cubrirse con el apósito adhesivo apropiado","Enjuagarse con el desinfectante usado en las herramientas","Tocarse con las manos descubiertas"],"re":"Cubre la zona lesionada con un apósito adhesivo apropiado (y un protector de dedo o guante si conviene)."},
  {"id":15,"q":"Un implemento que tocó la sangre de un cliente debe:","opts":["Limpiarse y reutilizarse enseguida","Solo enjuagarse con agua","Limpiarse y luego desinfectarse antes de reutilizarse","Guardarse en el cajón sin lavar"],"re":"Un implemento contaminado con sangre debe limpiarse y luego desinfectarse (o desecharse si es de un solo uso) antes de tocar a otra persona."},
  {"id":16,"q":"Para evitar contaminar un producto estíptico tras un corte, debes:","opts":["Presionar la barra o el frasco estíptico directamente sobre la herida abierta","Compartir una barra estíptica entre varios clientes sobre la piel","Meter el dedo y reutilizarlo","No dejar que el envase, la boquilla ni el estíptico toquen la piel o la herida"],"re":"No dejes que el envase, la boquilla ni el producto estíptico toquen la piel o la herida; dispénsalo de modo que la fuente no se contamine."},
  {"id":17,"q":"Los artículos empapados de sangre, como apósitos usados, deben desecharse:","opts":["En un recipiente sellado o marcado, manejado correctamente según el procedimiento del lugar","En un bote de basura abierto sobre la estación","Tirándolos por el lavabo","En la bolsa de un cliente"],"re":"Los residuos empapados de sangre deben manejarse y desecharse siguiendo los procedimientos adecuados para que nadie quede expuesto."},
  {"id":18,"q":"La mejor forma de proteger tus propias manos de la sangre durante una limpieza es:","opts":["Aguantar la respiración","Usar guantes desechables","Trabajar más rápido","Usar más colonia"],"re":"Los guantes desechables son la barrera clave que protege tus manos del contacto con sangre durante una limpieza."},
  {"id":19,"q":"Un artículo poroso, como un palillo de naranjo de madera o una lima de un solo uso, debe:","opts":["Desinfectarse y reutilizarse con el siguiente cliente","Limpiarse con alcohol y reutilizarse","Desecharse después de un uso (o dárselo al cliente)","Hervirse y reutilizarse"],"re":"Los artículos porosos de un solo uso no se pueden desinfectar; deséchalos tras un cliente o entrégalos a ese cliente para llevar a casa."},
  {"id":20,"q":"Las toallas y los textiles limpios en una estación deben:","opts":["Reutilizarse con varios clientes para ahorrar lavado","Dejarse amontonados en el piso","Compartirse entre el cliente y el estilista","Usarse con un solo cliente y luego guardarse cubiertos hasta lavarse"],"re":"Un textil se usa con un solo cliente; los limpios se guardan cubiertos y los sucios van a un recipiente cerrado hasta lavarse."},
  {"id":21,"q":"Las toallas y capas sucias deben guardarse en:","opts":["Un recipiente cerrado o cubierto rotulado para artículos sucios","Una canasta abierta sobre el mostrador","El mismo cajón que los textiles limpios","La zona de espera de clientes, sin cubrir"],"re":"Los textiles usados deben guardarse en un recipiente cerrado (a menudo rotulado «sucio») y separados de lo limpio hasta lavarse."},
  {"id":22,"q":"Los implementos desinfectados deben guardarse:","opts":["Mezclados con herramientas sucias","En un lugar limpio y cubierto, separados de los artículos sucios","En el piso descubierto","En un bolsillo con herramientas usadas"],"re":"Guarda las herramientas limpias y desinfectadas en un recipiente limpio y cubierto, apartadas de los implementos usados o sucios."},
  {"id":23,"q":"Después de cada cliente, la tina de un spa de pies de pedicura debe limpiarse y circular desinfectante durante al menos:","opts":["10 segundos","2 minutos","10 minutos","No se requiere tiempo"],"re":"California exige hacer circular por la tina un desinfectante hospitalario registrado por la EPA, bien medido, durante al menos 10 minutos después de cada cliente."},
  {"id":24,"q":"Las reglas de California exigen un registro de limpieza del spa de pies de pedicura que anote:","opts":["La fecha, la hora y las iniciales que muestran que la tina se limpió","Nada en particular","Las propinas del cliente","Las ventas al por menor"],"re":"El registro obligatorio del equipo de pedicura documenta cada limpieza con la fecha, la hora y las iniciales de quien la realizó."},
  {"id":25,"q":"Al sacar cera de una olla de cera para un servicio, debes:","opts":["Hundir varias veces la misma paleta en la olla","Usar una paleta limpia y no volver a meterla en la cera comunitaria","Reutilizar una paleta con varios clientes","Meter el dedo enguantado en la olla"],"re":"No reintroduzcas la paleta usada; vuelve a meter piel, vello y microbios en la cera compartida. Usa una paleta limpia o una porción de un solo cliente."},
  {"id":26,"q":"Los profesionales deben lavarse las manos:","opts":["Solo al final del día","Solo si las manos se ven sucias","Antes y después de atender a cada cliente","Una vez por semana"],"re":"Lavarse las manos antes y después de cada cliente es un paso básico y esencial para prevenir la propagación de infecciones."},
  {"id":27,"q":"Un pulidor o lima que tocó piel o uñas lastimadas o enfermas debe:","opts":["Limpiarse y reutilizarse","Guardarse para el mismo cliente el próximo mes","Rociarse con agua","Desecharse de inmediato tras el uso"],"re":"Si un artículo poroso toca piel o uñas lastimadas, infectadas o enfermas, deséchalo de inmediato en vez de reutilizarlo."},
  {"id":28,"q":"El buen orden y limpieza del salón ayuda principalmente a:","opts":["Aumentar los vapores químicos","Hacer que los servicios tarden más","Subir la temperatura","Prevenir la propagación de infecciones y reducir riesgos de resbalones/tropiezos"],"re":"Una estación limpia y ordenada reduce la contaminación, el riesgo de infección y los peligros de tropiezo para el personal y los clientes."},
  {"id":29,"q":"SDS significa:","opts":["Hoja de Datos de Seguridad (Safety Data Sheet)","Norma de Desinfección del Salón","Horario Diario Estándar","Hoja de Tareas de Sanidad"],"re":"Una SDS es una Hoja de Datos de Seguridad: el documento que describe los peligros de un producto y su manejo seguro."},
  {"id":30,"q":"Una Hoja de Datos de Seguridad moderna tiene cuántas secciones estandarizadas?","opts":["3","16","8","50"],"re":"Bajo la norma alineada con el GHS, una SDS tiene 16 secciones estandarizadas."},
  {"id":31,"q":"¿Dónde deben mantenerse las Hojas de Datos de Seguridad en el salón?","opts":["Guardadas bajo llave en el auto del dueño","Solo en el fabricante","Accesibles para los empleados donde puedan leerlas","Trituradas tras la compra"],"re":"El empleador debe tener una SDS de cada producto y mantenerla fácilmente accesible para los trabajadores."},
  {"id":32,"q":"Para conocer las medidas de primeros auxilios de un producto y qué hacer ante un derrame, consultas la:","opts":["Etiqueta de precio","Agenda de citas","Folleto de venta","Hoja de Datos de Seguridad"],"re":"La SDS indica las medidas de primeros auxilios, el manejo, el almacenamiento y la respuesta ante derrames de cada químico."},
  {"id":33,"q":"El «trío tóxico» de químicos de preocupación en productos para uñas se refiere a:","opts":["Tolueno, formaldehído y ftalato de dibutilo (DBP)","Agua, oxígeno y sal","Azúcar, almidón y harina","Hierro, cobre y zinc"],"re":"El «trío tóxico» es tolueno, formaldehído y ftalato de dibutilo (DBP), químicos que históricamente se encontraban en algunos productos para uñas."},
  {"id":34,"q":"La mejor manera de reducir la inhalación de vapores de productos como acetona y monómeros es:","opts":["Cerrar todas las ventanas y puertas","Tener buena ventilación y evitar respirar vapores concentrados","Encender una vela","Apagar las luces"],"re":"Una buena ventilación reduce la concentración de vapores; mantén los productos tapados y evita respirar vapores concentrados."},
  {"id":35,"q":"Los recipientes y frascos de químicos en el salón deben:","opts":["Estar sin etiqueta","Marcarse solo con una carita feliz","Estar claramente etiquetados para identificar el contenido","Guardarse junto a una llama abierta"],"re":"Todo recipiente de químicos debe estar etiquetado para que cualquiera identifique el contenido y sus peligros."},
  {"id":36,"q":"Muchos químicos del salón son inflamables, así que deben mantenerse lejos de:","opts":["Toallas limpias","La lista de precios","Solo la luz del día","Calor, chispas y llamas abiertas"],"re":"La acetona y muchos otros productos del salón son inflamables y deben guardarse lejos del calor, las chispas y las llamas abiertas."},
  {"id":37,"q":"Si un químico fuerte salpica en los ojos de un cliente o en los tuyos, debes:","opts":["Enjuagar el ojo con agua y seguir la guía de primeros auxilios de la SDS","Frotar el ojo con fuerza","Aplicar más producto","Ignorarlo"],"re":"Enjuaga el ojo con agua y sigue las instrucciones de primeros auxilios de la SDS; busca atención médica para exposiciones graves."},
  {"id":38,"q":"La Junta de Barbería y Cosmetología de California funciona bajo el/la:","opts":["OSHA federal","Departamento de Asuntos del Consumidor","Servicio Postal de EE. UU.","Departamento de Agricultura"],"re":"La Junta forma parte del Departamento de Asuntos del Consumidor de California, que supervisa los programas de licencias."},
  {"id":39,"q":"En California, una licencia de barbería o cosmetología generalmente debe renovarse:","opts":["Cada 6 meses","Una vez y nunca más","Cada dos años","Solo cuando te mudas"],"re":"Las licencias de California se renuevan en un ciclo de dos años."},
  {"id":40,"q":"Las reglas de salud y seguridad que un establecimiento debe seguir se encuentran en las/los:","opts":["Folleto de marketing","Publicaciones en redes sociales","Menú de precios","Leyes y reglamentos de la Junta (Artículo 12, Salud y Seguridad)"],"re":"Los reglamentos de Salud y Seguridad de la Junta (Artículo 12) establecen los requisitos de sanidad y desinfección para los licenciatarios."},
  {"id":41,"q":"Durante una inspección de la Junta, es más probable que el inspector verifique que:","opts":["Se cumplan las reglas de desinfección y sanidad","La música esté puesta","Las sillas sean de cierto color","El dueño sea amable"],"re":"Los inspectores verifican el cumplimiento de los requisitos de sanidad y desinfección, de las áreas más citadas por infracciones."},
  {"id":42,"q":"Un negocio que ofrece servicios regulados por la Junta generalmente necesita:","opts":["Ninguna licencia","Una licencia de establecimiento (salón) además de las licencias de los profesionales","Solo un permiso de estacionamiento municipal","Solo una tarjeta de presentación"],"re":"Se requiere una licencia de establecimiento para ofrecer servicios regulados por la Junta, junto con las licencias individuales de los profesionales."},
  {"id":43,"q":"Los cursos de desinfección y sanidad son parte de la formación en California porque:","opts":["Rellenan el tiempo","Son datos opcionales","Proteger la salud del cliente y del trabajador es un deber central de la licencia","No tienen nada que ver con el trabajo"],"re":"El control de infecciones es una parte obligatoria y evaluada de la formación en California porque prevenir la transmisión de enfermedades es central en la profesión."},
  {"id":44,"q":"Si una herramienta no se puede limpiar ni desinfectar (es porosa o de un solo uso), las reglas dicen que debes:","opts":["Reutilizarla de todos modos","Compartirla entre clientes","Guardarla con las herramientas desinfectadas","Usarla una vez y desecharla"],"re":"Los artículos que no se pueden desinfectar correctamente deben ser de un solo uso y desecharse; las reglas no permiten reutilizarlos en otros."},
  {"id":45,"q":"Para un corte leve con sangrado ligero, el primer paso básico es:","opts":["Aplicar presión firme y directa con una barrera limpia","Agitar la herida en el aire","Echarle producto","Apretarla más para que sangre más"],"re":"La presión directa con un apósito o barrera limpia es el primer paso más eficaz para controlar un sangrado leve."},
  {"id":46,"q":"Antes de dar primeros auxilios que puedan involucrar sangre, debes:","opts":["Quitarte cualquier guante","Ponerte guantes desechables si están disponibles","Tocar la herida con las manos descubiertas","No hacer nada de protección"],"re":"Ponte guantes desechables (u otra barrera) antes de tocar sangre para protegerte de los patógenos transmitidos por sangre."},
  {"id":47,"q":"Si un cliente de pronto tiene dificultad para respirar o muestra señales de una emergencia médica grave, debes:","opts":["Terminar primero el servicio","Esperar una hora a ver si pasa","Llamar a los servicios de emergencia (911) de inmediato","Darle un producto químico"],"re":"Las emergencias médicas graves requieren llamar al 911 de inmediato en vez de demorarse por el servicio."},
  {"id":48,"q":"Para proteger a un cliente, antes de un servicio químico como tinte o permanente debes:","opts":["Omitir cualquier prueba","Usar la fórmula más fuerte posible","Evitar preguntar sobre alergias","Considerar una prueba de parche o de mecha y revisar las sensibilidades según se indique"],"re":"Verificar las sensibilidades (por ejemplo, una prueba de parche donde se indique) ayuda a prevenir reacciones alérgicas y protege al cliente."},
  {"id":49,"q":"Si un cliente tiene una afección contagiosa de piel o cuero cabelludo, o una llaga abierta en la zona, debes:","opts":["No realizar el servicio sobre la zona afectada y derivarlo a un médico cuando corresponda","Atenderlo como de costumbre","Usar una herramienta porosa y reutilizarla","Ocultárselo a tu supervisor"],"re":"No des servicio sobre piel infectada o lastimada; deriva al cliente a un médico cuando corresponda para proteger a todos."},
  {"id":50,"q":"Un botiquín de primeros auxilios en el salón debe:","opts":["Estar vacío","Estar surtido y accesible para lesiones menores","Guardarse bajo llave fuera del lugar","Ser solo para el dueño"],"re":"Un botiquín surtido y accesible permite al personal responder rápido a cortes y lesiones menores."}
];
